t.script:
function callOdoo(url, callback) {
    fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: {} })
    })
    .then(response => response.json())
    .then(data => {
        if (data.error) {
            callback({error: data.error.message});
        } else {
            callback(data.result);
        }
    })
    .catch(error => {
        console.error('Error:', error);
        callback({error: 'Không thể kết nối'});
    });
}

function toggleJobPublish(jobId, currentPublished) {
    callOdoo('/my/recruitment/job/' + jobId + '/toggle_publish', function(data) {
        if (data.success) {
            showToast('Thành công', data.message, 'success');
            setTimeout(() => location.reload(), 1000);
        } else {
            showToast('Lỗi', data.error || 'Đã xảy ra lỗi', 'error');
        }
    });
}

let pendingJobId = null;

function setPendingJob(jobId) {
    pendingJobId = jobId;
}

function executePendingClose() {
    if (!pendingJobId) return;
    callOdoo('/my/recruitment/job/' + pendingJobId + '/close', function(data) {
        if (data.success) {
            showToast('Thành công', data.message, 'success');
            setTimeout(() => location.reload(), 1000);
        } else {
            showToast('Lỗi', data.error || 'Đã xảy ra lỗi', 'error');
        }
        pendingJobId = null;
    });
}

function reopenJob(jobId) {
    callOdoo('/my/recruitment/job/' + jobId + '/reopen', function(data) {
        if (data.success) {
            showToast('Thành công', data.message, 'success');
            setTimeout(() => location.reload(), 1000);
        } else {
            showToast('Lỗi', data.error || 'Đã xảy ra lỗi', 'error');
        }
    });
}

function showToast(title, message, type) {
    var toastEl = document.getElementById('job-toast');
    var icon = document.getElementById('toast-icon');
    document.getElementById('toast-title').textContent = title;
    document.getElementById('toast-message').textContent = message;

    toastEl.className = 'toast align-items-center border-0 text-white';

    if (type === 'error') {
        toastEl.classList.add('bg-danger');
        icon.className = 'fa fa-times-circle fa-lg';
    } else {
        toastEl.classList.add('bg-success');
        icon.className = 'fa fa-check-circle fa-lg';
    }

    toastEl.classList.add('show');
    setTimeout(() => toastEl.classList.remove('show'), 3000);
}
